// Build Apollo search parameters from trigger context
const webhookData = $input.first().json;
const isWebhook = !!(webhookData.body && (webhookData.body.regions || webhookData.body.queries || webhookData.body.audience_type));

// Default search config for auto repair vertical
let industryTags = ['auto_repair'];
let employeeRanges = ['1,10', '11,20', '21,50'];
let locations = ['United States'];
let personTitles = ['owner', 'manager', 'general manager', 'service manager', 'shop owner'];
let perPage = 100;

if (isWebhook) {
  const body = webhookData.body;

  // Override industry/audience if provided
  if (body.audience_type) {
    const audienceMap = {
      'auto_repair': ['auto_repair'],
      'salon': ['beauty_salon', 'hair_salon'],
      'hvac': ['hvac'],
      'plumbing': ['plumbing'],
      'dental': ['dental_practice'],
      'fitness': ['fitness', 'gym']
    };
    industryTags = audienceMap[body.audience_type] || [body.audience_type];
  }

  // Override locations if regions provided
  if (body.regions && body.regions.length > 0) {
    // Apollo accepts state names directly
    locations = body.regions.map(r => r + ', United States');
  }

  // Override person titles if queries suggest different roles
  if (body.queries && body.queries.length > 0) {
    // Treat queries as additional title search terms
    personTitles = [...new Set([...personTitles, ...body.queries])];
  }
}

// Track pagination via static data
const staticData = $getWorkflowStaticData('global');
if (!staticData.apolloPage) staticData.apolloPage = 1;
if (!staticData.totalOrgsProcessed) staticData.totalOrgsProcessed = 0;
if (!staticData.lastRunDate) staticData.lastRunDate = '';

// Reset page counter each week (new run)
const today = $now.toFormat('yyyy-MM-dd');
if (staticData.lastRunDate !== today) {
  staticData.apolloPage = 1;
  staticData.lastRunDate = today;
}

const currentPage = staticData.apolloPage;

return [{
  json: {
    industryTags,
    employeeRanges,
    locations,
    personTitles,
    perPage,
    currentPage,
    isWebhook
  }
}];

const response = $input.first().json;
const searchParams = $('Build Apollo Search Params').first().json;

// Update pagination state
const staticData = $getWorkflowStaticData('global');

const organizations = response.organizations || response.accounts || [];

if (!organizations || organizations.length === 0) {
  // Reset page for next run
  staticData.apolloPage = 1;
  return [{ json: { _empty: true, reason: 'No organizations found from Apollo. Page: ' + searchParams.currentPage, totalProcessed: staticData.totalOrgsProcessed || 0 } }];
}

// Advance page for next batch
staticData.apolloPage = (staticData.apolloPage || 1) + 1;

// Extract org data
return organizations.map(org => ({
  json: {
    org_id: org.id || org.organization_id || '',
    business_name: org.name || '',
    website: org.website_url || org.primary_domain || '',
    domain: (org.primary_domain || org.website_url || '').replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0],
    phone: org.phone || org.sanitized_phone || '',
    industry: org.industry || '',
    company_size: org.estimated_num_employees ? String(org.estimated_num_employees) : (org.num_employees_ranges ? org.num_employees_ranges[0] : ''),
    annual_revenue: org.annual_revenue_printed || org.annual_revenue || '',
    city: org.city || '',
    state: org.state || '',
    country: org.country || 'United States',
    technologies: org.technologies || [],
    linkedin_url: org.linkedin_url || '',
    apollo_org_id: org.id || org.organization_id || '',
    personTitles: searchParams.personTitles
  }
}));

const response = $input.first().json;
const orgData = $('Has Organizations?').first().json;

const people = response.people || response.contacts || [];

if (!people || people.length === 0) {
  return [{ json: { _empty: true, reason: 'No decision makers found for ' + orgData.business_name, org_id: orgData.org_id } }];
}

// Take the top person (most senior / best match)
const best = people[0];

return [{
  json: {
    apollo_id: best.id || '',
    first_name: best.first_name || '',
    last_name: best.last_name || '',
    title: best.title || '',
    seniority: best.seniority || '',
    email: best.email || '',
    phone: best.phone_numbers ? (best.phone_numbers[0] || {}).sanitized_number || '' : (orgData.phone || ''),
    linkedin_url: best.linkedin_url || orgData.linkedin_url || '',
    person_city: best.city || '',
    person_state: best.state || '',
    // Carry forward org data
    business_name: orgData.business_name,
    website: orgData.website,
    domain: orgData.domain,
    industry: orgData.industry,
    company_size: orgData.company_size,
    annual_revenue: orgData.annual_revenue,
    city: orgData.city || best.city || '',
    state: orgData.state || best.state || '',
    technologies: orgData.technologies,
    apollo_org_id: orgData.apollo_org_id
  }
}];

const enriched = $input.first().json;
const prevData = $('Found Decision Maker?').first().json;

const person = enriched.person || enriched;

// Get email - prefer work email, fallback to personal
let email = '';
if (person.email) {
  email = person.email;
} else if (person.personal_emails && person.personal_emails.length > 0) {
  email = person.personal_emails[0];
} else if (prevData.email) {
  email = prevData.email;
}

// Get phone
let phone = prevData.phone || '';
if (person.phone_numbers && person.phone_numbers.length > 0) {
  phone = person.phone_numbers[0].sanitized_number || person.phone_numbers[0].number || phone;
} else if (person.phone) {
  phone = person.phone;
}

if (!email) {
  return [{ json: { _skip: true, reason: 'No email found after enrichment', business_name: prevData.business_name, apollo_id: prevData.apollo_id } }];
}

return [{
  json: {
    ...prevData,
    email,
    phone,
    linkedin_url: person.linkedin_url || prevData.linkedin_url || '',
    title: person.title || prevData.title || '',
    seniority: person.seniority || prevData.seniority || ''
  }
}];

const dupeCheck = $input.first().json;
const leadData = $('Has Email?').first().json;

const results = Array.isArray(dupeCheck) ? dupeCheck : [];

if (results.length > 0) {
  return [{ json: { _skip: true, reason: 'Duplicate - already in Supabase', email: leadData.email, business_name: leadData.business_name } }];
}

return [{ json: { ...leadData, _skip: false } }];

const verifyResponse = $input.first().json;
const leadData = $('Not Duplicate?').first().json;

const result = (verifyResponse.result || '').toLowerCase();
const acceptable = ['ok', 'catch_all'];

if (!acceptable.includes(result)) {
  return [{
    json: {
      _skip: true,
      reason: 'Email validation failed: ' + result,
      email: leadData.email,
      business_name: leadData.business_name
    }
  }];
}

return [{
  json: {
    ...leadData,
    email_verified: true,
    email_verify_result: result
  }
}];

const allSaved = $input.all();
const now = new Date();
const dateStr = $now.toFormat('yyyy-MM-dd');

let savedCount = 0;
let failedCount = 0;
const statesSeen = new Set();
const savedLeads = [];

for (const item of allSaved) {
  const d = item.json;
  if (d.id || (Array.isArray(d) && d.length > 0)) {
    savedCount++;
    const lead = Array.isArray(d) ? d[0] : d;
    if (lead.state) statesSeen.add(lead.state);
    savedLeads.push({
      business: lead.business_name || 'Unknown',
      email: lead.email || 'N/A',
      title: lead.title || 'N/A',
      city: lead.city || 'N/A',
      state: lead.state || 'N/A'
    });
  } else {
    failedCount++;
  }
}

const staticData = $getWorkflowStaticData('global');
staticData.totalOrgsProcessed = (staticData.totalOrgsProcessed || 0) + savedCount;

let report = `# Apollo Lead Gen Report - ${dateStr}\n\n`;
report += `## Summary\n`;
report += `- **Date**: ${now.toISOString()}\n`;
report += `- **New validated leads saved**: ${savedCount}\n`;
report += `- **Failed/skipped**: ${failedCount}\n`;
report += `- **States covered**: ${Array.from(statesSeen).join(', ')}\n`;
report += `- **Total leads processed to date**: ${staticData.totalOrgsProcessed}\n`;
report += `- **Apollo page**: ${staticData.apolloPage || 1}\n\n`;

if (savedLeads.length > 0) {
  report += `## New Leads\n\n`;
  report += `| Business | Email | Title | City | State |\n`;
  report += `|----------|-------|-------|------|-------|\n`;
  for (const lead of savedLeads) {
    report += `| ${lead.business} | ${lead.email} | ${lead.title} | ${lead.city} | ${lead.state} |\n`;
  }
}

return [{
  json: {
    report,
    dateStr,
    savedCount,
    failedCount,
    totalProcessed: staticData.totalOrgsProcessed,
    telegramMessage: `Apollo Lead Gen: Found ${savedCount} new validated leads. States: ${Array.from(statesSeen).join(', ')}. Total to date: ${staticData.totalOrgsProcessed}. Failed/skipped: ${failedCount}.`
  }
}];

const data = $input.first().json;
return [{
  json: {
    telegramMessage: 'Apollo Lead Gen: No organizations found. All pages exhausted or API issue. Total processed: ' + (data.totalProcessed || 'unknown') + '.',
    _complete: true
  }
}];
